import { NextResponse } from 'next/server';
import fs from 'fs';
import path from 'path';

/**
 * GET /api/backtest/results
 * Returns the latest ML backtest results and signal data from the pipeline.
 * Reads from the JSON files generated by the Python scripts.
 */
export async function GET() {
  try {
    const dataDir = path.join(process.cwd(), 'data');
    const resultsDir = path.join(dataDir, 'backtest_results');

    // ── Find latest ML backtest result ──────────────────────
    let latestBacktest = null;
    if (fs.existsSync(resultsDir)) {
      const files = fs.readdirSync(resultsDir)
        .filter((f: string) => f.startsWith('ml_backtest_') && f.endsWith('.json'))
        .sort()
        .reverse();

      if (files.length > 0) {
        const content = fs.readFileSync(path.join(resultsDir, files[0]), 'utf-8');
        latestBacktest = JSON.parse(content);
      }
    }

    // ── Load alpha signals ──────────────────────────────────
    let alphaSignals = null;
    const signalsPath = path.join(dataDir, 'alpha_signals.json');
    if (fs.existsSync(signalsPath)) {
      const content = fs.readFileSync(signalsPath, 'utf-8');
      alphaSignals = JSON.parse(content);
    }

    // ── Load IV surface summary ──────────────────────────────
    let ivSurface = null;
    const ivPath = path.join(dataDir, 'btc_iv_surface.json');
    if (fs.existsSync(ivPath)) {
      const content = fs.readFileSync(ivPath, 'utf-8');
      const raw = JSON.parse(content);
      // Send summary only, not full surface (too large)
      ivSurface = {
        currency:     raw.currency,
        indexPrice:   raw.index_price,
        fetchedAt:    raw.fetched_at,
        nExpiries:    Object.keys(raw.surface || {}).length,
        nInstruments: raw.n_instruments,
        expiries:     Object.keys(raw.surface || {}),
      };
    }

    // ── Trust score distribution ────────────────────────────
    let trustDistribution = null;
    const trustPath = path.join(dataDir, 'trust_scores_historical.parquet');
    if (fs.existsSync(trustPath)) {
      // Read parquet summary from the JSON backtest result instead
      if (latestBacktest?.ml_metrics) {
        trustDistribution = {
          nMarkets:   latestBacktest.n_markets,
          riskRate:   latestBacktest.ml_metrics.risk_rate,
          aucRoc:     latestBacktest.ml_metrics.auc_roc,
          brierScore: latestBacktest.ml_metrics.brier_cal,
        };
      }
    }

    return NextResponse.json({
      status:      'ok',
      dataExists:  latestBacktest !== null,
      backtest:    latestBacktest,
      signals:     alphaSignals,
      ivSurface,
      trustSummary: trustDistribution,
    });

  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : 'Unknown error';
    console.error('[api/backtest/results]', message);
    return NextResponse.json({ status: 'error', message }, { status: 500 });
  }
}
